import { codeToHtml } from "shiki"
import { CodeBlockFrame } from "./CodeBlockFrame"

interface CodeBlockProps {
  code: string
  language?: string
  filename?: string
  filepath?: string
  highlightLines?: number[]
  showLineNumbers?: boolean
  startingLineNumber?: number
}

function decorateShikiHtml(
  html: string,
  highlightLines: number[],
  showLineNumbers: boolean,
  startingLineNumber: number
): string {
  let lineIndex = 0

  return html.replace(/<span class="line">/g, () => {
    const lineNumber = startingLineNumber + lineIndex
    lineIndex += 1

    const classes = ["line"]

    if (showLineNumbers) {
      classes.push("code-line-numbered")
    }

    if (highlightLines.includes(lineNumber)) {
      classes.push("highlight-line")
    }

    return `<span class="${classes.join(" ")}" data-line="${lineNumber}">`
  })
}

function patchPreTag(html: string): string {
  return html.replace(
    /<pre class="shiki/g,
    '<pre class="shiki codeblock-pre scrollbar-hidden'
  )
}

export async function renderCodeBlockHtml({
  code,
  language = "ts",
  highlightLines = [],
  showLineNumbers = true,
  startingLineNumber = 1,
}: {
  code: string
  language?: string
  highlightLines?: number[]
  showLineNumbers?: boolean
  startingLineNumber?: number
}) {
  if (!code || !code.trim()) {
    return `<div class="px-4 py-4 text-sm text-white/45">empty code block</div>`
  }

  let html = await codeToHtml(code, {
    lang: language,
    theme: "vitesse-dark",
  })

  html = patchPreTag(html)
  html = decorateShikiHtml(
    html,
    highlightLines,
    showLineNumbers,
    startingLineNumber
  )

  return html
}

export async function CodeBlock({
  code,
  language = "ts",
  filename,
  filepath,
  highlightLines = [],
  showLineNumbers = true,
  startingLineNumber = 1,
}: CodeBlockProps) {
  const html = await renderCodeBlockHtml({
    code,
    language,
    highlightLines,
    showLineNumbers,
    startingLineNumber,
  })

  return (
    <CodeBlockFrame
      html={html}
      code={code}
      language={language}
      filename={filename}
      filepath={filepath}
    />
  )
}

export default CodeBlock